/// <summary>
/// Scoped service that holds the latest low-stock alert count for the
/// current circuit. Components subscribe to <see cref="OnChange"/> to
/// be notified when new data arrives.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public int CurrentCount { get; private set; }

    /// <summary>
    /// Fired after <see cref="CurrentCount"/> is updated.
    /// Subscribers on background threads must wrap StateHasChanged in InvokeAsync.
    /// </summary>
    public event Action? OnChange;

    /// <summary>
    /// Simulates a database query that returns the number of items
    /// below minimum stock levels for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Updates <see cref="CurrentCount"/> and notifies all subscribers.
    /// Called by the component that owns the polling timer.
    /// </summary>
    public void UpdateCount(int newCount)
    {
        CurrentCount = newCount;
        OnChange?.Invoke();
    }
}

