@rendermode InteractiveServer
@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@using sv_90d10925f521402182ee90295e8efe1a.Services

<select class="form-select form-select-sm" style="width: auto;"
        value="@_selectedId" @onchange="OnWarehouseChanged">
    @foreach (var (id, name) in WarehouseInfo.Available)
    {
        <option value="@id">@name</option>
    }
</select>

@code {
    private string _selectedId = "warehouse-a";

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        _selectedId = e.Value?.ToString() ?? "warehouse-a";
        var match = WarehouseInfo.Available
            .FirstOrDefault(w => w.Id == _selectedId);

        var info = new WarehouseInfo
        {
            WarehouseId = _selectedId,
            DisplayName = match.Name ?? _selectedId
        };

        await WarehouseSource.NotifyChangedAsync(info);
    }
}

@rendermode InteractiveServer
@inject InventoryAlertService Alerts
@implements IDisposable
@using sv_90d10925f521402182ee90295e8efe1a.Services

@if (Alerts.CurrentCount > 0)
{
    <span class="badge bg-danger rounded-pill">@Alerts.CurrentCount</span>
}
else
{
    <span class="badge bg-secondary rounded-pill">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Timer fires on a background thread, so wrap in InvokeAsync.
        _handler = () => InvokeAsync(StateHasChanged);
        Alerts.OnChange += _handler;
    }

    public void Dispose()
    {
        Alerts.OnChange -= _handler;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@inject InventoryAlertService Alerts
@implements IDisposable
@using sv_90d10925f521402182ee90295e8efe1a.Services

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard — @(Warehouse?.DisplayName ?? "loading…")</h1>

<div class="card mt-3" style="max-width: 28rem;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text display-4">
            @if (Alerts.CurrentCount > 0)
            {
                <span class="text-danger">@Alerts.CurrentCount</span>
            }
            else
            {
                <span class="text-success">0</span>
            }
        </p>
        <p class="text-muted">
            Items below minimum stock level. Refreshes every 10 seconds.
        </p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Subscribe so this component re-renders when count changes
        // (timer fires from a background thread → InvokeAsync).
        _handler = () => InvokeAsync(StateHasChanged);
        Alerts.OnChange += _handler;
    }

    protected override async Task OnParametersSetAsync()
    {
        // (Re-)start polling whenever the warehouse changes.
        await RestartPollingAsync();
    }

    private async Task RestartPollingAsync()
    {
        // Cancel any running poll loop.
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        // Fetch immediately, then poll.
        await PollAsync();

        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await PollAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected when navigating away or changing warehouse.
        }
    }

    private async Task PollAsync()
    {
        var warehouseId = Warehouse?.WarehouseId ?? "warehouse-a";
        var count = await Alerts.GetLowStockCountAsync(warehouseId);
        // UpdateCount fires OnChange, which notifies ALL subscribers
        // (AlertBadge in the sidebar and this Dashboard page).
        Alerts.UpdateCount(count);
    }

    public void Dispose()
    {
        Alerts.OnChange -= _handler;
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
    }
}

